
/* eslint-disable global-require */
/* eslint-disable @typescript-eslint/no-var-requires */
/* eslint-disable camelcase */
/* eslint-ignore */

import Vue from 'vue'
import { _T, getArgsFromUrl, getSysTs, sprintf } from '@badam/common-utils'
import { showToast } from '@/components/toast/toast.vue'
import store from '@/store'
import { loginWithApple, loginWithFacebook, loginWithGoogle } from '@/api'
import { Events, reportEvent } from '@/event'
import { CLIENT_ID, getSub, refreshAccount, showBanToast, unregisterRemind } from '@/utils'
import { showModal } from '@/components/base/modal/modal.vue'
import { callbackToClient, goToMobileWebview, isTargetVersion } from '@/utils/new-login'
import CreateModal from './create-modal/index.vue'

declare let AppleID: any
declare let FB: any

export default Vue.extend({
  // eslint-disable-next-line vue/no-unused-components
  components: { CreateModal },
  data() {
    return {
      loading: false,
      sdkLoaded: true,
    }
  },
  mounted() {
    // eslint-disable-next-line @typescript-eslint/no-empty-function
    //
    if (localStorage.getItem('firstCome')) {
      reportEvent(Events.h5_loginpage, {
        is_first_time: false,
      })
    } else {
      localStorage.setItem('firstCome', '1')
      reportEvent(Events.h5_loginpage, {
        is_first_time: true,
      })
    }
    if (getArgsFromUrl('is_refresh')) {
      this.$router.push({ name: 'Mobile' })
    }
  },
  async created() {
    // todo
  },
  computed: {
    googleLoad() {
      return store.state.googleLoad
    },
    policy() {
      const src1 = 'https://isawa.badambiz.com/html/user_agreement_ksa.html'
      const src2 = 'https://isawa.badambiz.com/html/privacy_policy_ksa.html'
      return sprintf(
        _T('点击登录意味着你已经同意遵守{appname}的{terms_of_service}和{privacy_policy}'),
        {
          appname: 'Sawa',
          terms_of_service: `<a href=${src1} class='a'>${_T('服务条款')}</a>`,
          privacy_policy: `<a href=${src2} class='a'>${_T('隐私政策')}</a>`,
        }
      )
    },
  },
  watch: {
    googleLoad(newValue, oldValue) {
      if (newValue) {
        this.attachSignin()
        setTimeout(() => {
          this.sdkLoaded = true
        }, 100)
      }
    },
  },
  methods: {
    _T,
    async onPressApple() {
      try {
        this.loading = true
        reportEvent(Events.h5_loginpage_elementclick, {
          element_name: 'apple',
        })
        const data = await AppleID.auth.signIn()
        console.log('data', data)
        if (!data || !data.authorization || !data.authorization.id_token) {
          this.loading = false
          return
        }

        const { code: apple_uid, id_token: apple_token } = data.authorization
        const user_id = getSub(apple_token)
        this.loading = false
        this.doLoginApple(user_id, apple_token)
      } catch (error) {
        this.loading = false
      }
    },
    onPressGoogle() {
      //
    },
    onPhonePress() {
      //
      reportEvent(Events.h5_loginpage_elementclick, {
        element_name: 'phone',
      })
      if (isTargetVersion()) {
        goToMobileWebview()
        return
      }
      this.$router.push({ name: 'Mobile' })
    },
    async onPressFacebook() {
      console.log('onPressFacebook')
      reportEvent(Events.h5_loginpage_elementclick, {
        element_name: 'facebook',
      })
      FB.login((response: any) => {
        console.log('response', response)
        if (!response.authResponse) {
          this.loading = false
          return
        }
        const { userID: fb_uid, accessToken: fb_token } = response.authResponse
        this.doLoginFacebook(fb_uid, fb_token)
      })
    },
    showCreateModal(cb: any, source: string) {
      showModal(CreateModal, { cb, source })
    },
    async doLoginApple(apple_uid: string, apple_token: string, auto_create = false) {
      if (isTargetVersion()) {
        callbackToClient({
          login_type: 'apple',
          user_id: apple_uid,
          access_token: apple_token,
        })
        return
      }
      this.loading = true
      const [success, accountResp] = await loginWithApple(
        apple_uid,
        apple_token,
        undefined,
        auto_create
      )
      this.loading = false

      if (!success) {
        showToast(_T('获取数据失败，请稍后重试'))
        this.loading = false
        return
      }

      if (accountResp.result !== 0) {
        this.loading = false
        if (accountResp.result === 20001) {
          showBanToast(accountResp.message || '')
          return
        }
        if (accountResp.result === 20193) {
          unregisterRemind(accountResp)
          return
        }

        if (accountResp.result === 20312) {
          this.showCreateModal(() => this.doLoginApple(apple_uid, apple_token, true), 'apple')
        } else {
          showToast(accountResp.toast || _T('获取数据失败，请稍后重试'))
        }
        // todo 创建账号
        // this.showDialog(accountResp, apple_uid, apple_token, 'apple')
        return
      }

      refreshAccount(accountResp, 'sawaksa_apple')
    },
    async doLoginFacebook(fb_uid: string, fb_token: string, auto_create = false) {
      if (isTargetVersion()) {
        callbackToClient({
          login_type: 'facebook',
          user_id: fb_uid,
          access_token: fb_token,
        })
        return
      }
      if (this.loading) {
        return
      }
      this.loading = true
      const [success, accountResp] = await loginWithFacebook(fb_uid, fb_token, auto_create)
      this.loading = false

      if (!success) {
        showToast(_T('获取数据失败，请稍后重试'))
        this.loading = false
        return
      }

      if (accountResp.result !== 0) {
        this.loading = false
        if (accountResp.result === 20001) {
          showBanToast(accountResp.message || '')
          return
        }
        if (accountResp.result === 20193) {
          unregisterRemind(accountResp)
          return
        }

        if (accountResp.result === 20312) {
          this.showCreateModal(() => this.doLoginFacebook(fb_uid, fb_token, true), 'facebook')
        } else {
          showToast(accountResp.toast || _T('获取数据失败，请稍后重试'))
        }
        // todo 错误弹窗
        // this.showDialog(accountResp, fb_uid, fb_token, 'fb')
        return
      }

      console.log('facebook login rsp', accountResp, success)
      refreshAccount(accountResp, 'sawaksa_fb')
    },
    async doLoginGoogle(token: any, auto_create = false) {
      if (isTargetVersion()) {
        callbackToClient({
          login_type: 'google',
          id_token: token,
        })
        return
      }
      this.loading = true
      const [success, accountResp] = await loginWithGoogle(token, auto_create)
      this.loading = false

      console.log('google login data', success, accountResp)
      if (!success) {
        showToast(_T('获取数据失败，请稍后重试'))
        this.loading = false
        return
      }

      if (accountResp.result !== 0) {
        this.loading = false
        if (accountResp.result === 20001) {
          showBanToast(accountResp.message || '')
          return
        }
        if (accountResp.result === 20193) {
          unregisterRemind(accountResp)
          return
        }

        if (accountResp.result === 20312) {
          this.showCreateModal(() => this.doLoginGoogle(token, true), 'google')
        } else {
          showToast(accountResp.toast || _T('获取数据失败，请稍后重试'))
        }

        // todo 错误弹窗
        // this.showDialog(accountResp, fb_uid, fb_token, 'fb')
        return
      }

      console.log('google login rsp', accountResp, success)

      refreshAccount(accountResp, 'sawaksa_google')
    },
    attachSignin() {
      const { google } = window as any

      if (google) {
        google.accounts.id.initialize({
          client_id: CLIENT_ID,
          callback: (data: any) => {
            this.doLoginGoogle(data?.credential)
          },
        })
        google.accounts.id.renderButton(document.getElementById('google-login-btn'), {
          theme: 'outline',
          size: 'large',
          type: 'standard',
          width: '311',
        })
      }
    },
  },
})
