/* eslint-disable import/prefer-default-export */
import Vue from 'vue'
import 'vue-tsx-support/enable-check'
import App from './App'
import store from './store'
import { calculateWindow2, initAppleLogin, loadVConsoleIfNeed } from './utils/func'
import { initErrorHandler } from './utils/event'

Vue.config.productionTip = false

export const initBloot = () => {
  initAppleLogin()

  initErrorHandler()

  calculateWindow2()

  loadVConsoleIfNeed()

  new Vue({
    store,
    render: (h) => h(App),
  }).$mount('#app')
}
